import { useState, useEffect } from "react";
import { supabase } from "@/integrations/supabase/client";

const CACHE_KEY = "user_country";
const CACHE_TTL = 1000 * 60 * 60 * 24; // 24 hours

interface CachedCountry {
  country: string | null;
  timestamp: number;
}

export const useUserCountry = () => {
  const [country, setCountry] = useState<string | null>(() => {
    try {
      const cached = localStorage.getItem(CACHE_KEY);
      if (cached) {
        const parsed: CachedCountry = JSON.parse(cached);
        if (Date.now() - parsed.timestamp < CACHE_TTL) {
          return parsed.country;
        }
      }
    } catch {}
    return null;
  });
  const [isLoading, setIsLoading] = useState(() => {
    try {
      const cached = localStorage.getItem(CACHE_KEY);
      if (cached) {
        const parsed: CachedCountry = JSON.parse(cached);
        if (Date.now() - parsed.timestamp < CACHE_TTL) {
          return false;
        }
      }
    } catch {}
    return true;
  });

  useEffect(() => {
    // Skip if we have a valid cache
    try {
      const cached = localStorage.getItem(CACHE_KEY);
      if (cached) {
        const parsed: CachedCountry = JSON.parse(cached);
        if (Date.now() - parsed.timestamp < CACHE_TTL) {
          return;
        }
      }
    } catch {}

    const detectCountry = async () => {
      try {
        const { data, error } = await supabase.functions.invoke("get-location");
        if (error) throw error;
        
        const detectedCountry = data?.country || null;
        setCountry(detectedCountry);
        
        // Cache result
        localStorage.setItem(CACHE_KEY, JSON.stringify({
          country: detectedCountry,
          timestamp: Date.now(),
        } as CachedCountry));
      } catch (err) {
        console.warn("[useUserCountry] Failed to detect country:", err);
        setCountry(null);
      } finally {
        setIsLoading(false);
      }
    };

    detectCountry();
  }, []);

  return { country, isLoading };
};
